import type * as DMMF from '@prisma/dmmf'

/**
 * Returns the TypeScript type for a DMMF scalar or enum field value,
 * without considering field-level optionality.
 */
export function fieldBaseType(field: Pick<DMMF.Field, 'type' | 'isList' | 'kind'>): string {
  let baseType: string
  if (field.kind === 'scalar') {
    baseType = mapScalarType(field.type)
  } else if (field.kind === 'enum') {
    // Enum name used directly — it will be generated as a union type alias.
    baseType = field.type
  } else {
    return 'unknown'
  }
  return field.isList ? `${baseType}[]` : baseType
}

/**
 * Returns the full TypeScript type for a DMMF scalar or enum field,
 * including `| null` for optional (non-required) non-list fields.
 */
export function fieldToTsType(field: Pick<DMMF.Field, 'type' | 'isRequired' | 'isList' | 'kind'>): string {
  const base = fieldBaseType(field)
  if (!field.isRequired && !field.isList) {
    return `${base} | null`
  }
  return base
}

function mapScalarType(prismaType: string): string {
  switch (prismaType) {
    case 'String':
      return 'string'
    case 'Boolean':
      return 'boolean'
    case 'Int':
    case 'Float':
    case 'Decimal':
      return 'number'
    case 'BigInt':
      return 'bigint'
    case 'DateTime':
      return 'Date'
    case 'Json':
      return 'unknown'
    case 'Bytes':
      return 'Uint8Array'
    default:
      return 'unknown'
  }
}

