import type * as DMMF from '@prisma/dmmf'
import { afterEach, beforeEach, describe, expect, it } from 'vitest'

import { generateRestClient } from '../generate-rest-client'

// Minimal DMMF fixture with one model and one enum, sufficient for all code paths.
const testDmmf = {
  datamodel: {
    models: [
      {
        name: 'User',
        dbName: null,
        schema: null,
        uniqueFields: [],
        uniqueIndexes: [],
        primaryKey: { name: null, fields: ['id'] },
        fields: [
          {
            kind: 'scalar',
            name: 'id',
            type: 'Int',
            isRequired: true,
            isList: false,
            isUnique: false,
            isId: true,
            isReadOnly: false,
            hasDefaultValue: true,
            default: { name: 'autoincrement', args: [] },
            isGenerated: false,
            isUpdatedAt: false,
          },
          {
            kind: 'scalar',
            name: 'email',
            type: 'String',
            isRequired: true,
            isList: false,
            isUnique: true,
            isId: false,
            isReadOnly: false,
            hasDefaultValue: false,
            isGenerated: false,
            isUpdatedAt: false,
          },
          {
            kind: 'scalar',
            name: 'name',
            type: 'String',
            isRequired: false,
            isList: false,
            isUnique: false,
            isId: false,
            isReadOnly: false,
            hasDefaultValue: false,
            isGenerated: false,
            isUpdatedAt: false,
          },
          {
            kind: 'enum',
            name: 'role',
            type: 'Role',
            isRequired: true,
            isList: false,
            isUnique: false,
            isId: false,
            isReadOnly: false,
            hasDefaultValue: true,
            default: 'USER',
            isGenerated: false,
            isUpdatedAt: false,
          },
          {
            // Relations are excluded from generated interfaces and input types.
            kind: 'object',
            name: 'posts',
            type: 'Post',
            isRequired: false,
            isList: true,
            isUnique: false,
            isId: false,
            isReadOnly: false,
            hasDefaultValue: false,
            isGenerated: false,
            isUpdatedAt: false,
            relationName: 'PostToUser',
            relationFromFields: [],
            relationToFields: [],
          },
        ],
      },
    ],
    enums: [
      {
        name: 'Role',
        values: [
          { name: 'USER', dbName: null },
          { name: 'ADMIN', dbName: null },
        ],
      },
