import * as fs from 'node:fs/promises'
import * as os from 'node:os'
import * as path from 'node:path'

import type * as DMMF from '@prisma/dmmf'
import { afterEach, beforeEach, describe, expect, it } from 'vitest'

import { generateRestClient } from '../generate-rest-client'

// Minimal DMMF fixture with one model and one enum, sufficient for all code paths.
const testDmmf = {
  datamodel: {
    models: [
      {
        name: 'User',
        dbName: null,
        schema: null,
        uniqueFields: [],
        uniqueIndexes: [],
        primaryKey: { name: null, fields: ['id'] },
        fields: [
          {
            kind: 'scalar',
            name: 'id',
            type: 'Int',
            isRequired: true,
            isList: false,
            isUnique: false,
            isId: true,
            isReadOnly: false,
            hasDefaultValue: true,
            default: { name: 'autoincrement', args: [] },
            isGenerated: false,
            isUpdatedAt: false,
          },
          {
            kind: 'scalar',
            name: 'email',
            type: 'String',
            isRequired: true,
            isList: false,
            isUnique: true,
            isId: false,
            isReadOnly: false,
            hasDefaultValue: false,
            isGenerated: false,
            isUpdatedAt: false,
          },
          {
            kind: 'scalar',
            name: 'name',
            type: 'String',
            isRequired: false,
            isList: false,
            isUnique: false,
            isId: false,
            isReadOnly: false,
            hasDefaultValue: false,
            isGenerated: false,
            isUpdatedAt: false,
          },
          {
            kind: 'enum',
            name: 'role',
            type: 'Role',
            isRequired: true,
            isList: false,
            isUnique: false,
            isId: false,
            isReadOnly: false,
            hasDefaultValue: true,
            default: 'USER',
            isGenerated: false,
            isUpdatedAt: false,
          },
          {
            // Relations are excluded from generated interfaces and input types.
            kind: 'object',
            name: 'posts',
            type: 'Post',
            isRequired: false,
            isList: true,
            isUnique: false,
            isId: false,
            isReadOnly: false,
            hasDefaultValue: false,
            isGenerated: false,
            isUpdatedAt: false,
            relationName: 'PostToUser',
            relationFromFields: [],
            relationToFields: [],
          },
        ],
      },
    ],
    enums: [
      {
        name: 'Role',
        values: [
          { name: 'USER', dbName: null },
          { name: 'ADMIN', dbName: null },
        ],
      },
    ],
    types: [],
    indexes: [],
  },
  schema: {} as DMMF.Schema,
  mappings: {} as DMMF.Mappings,
} satisfies DMMF.Document

describe('generateRestClient', () => {
  let tempDir: string

  beforeEach(async () => {
    tempDir = await fs.mkdtemp(path.join(os.tmpdir(), 'rest-api-gen-test-'))
  })

  afterEach(async () => {
    await fs.rm(tempDir, { recursive: true, force: true })
  })

  async function readOutput(): Promise<string> {
    return fs.readFile(path.join(tempDir, 'index.ts'), 'utf-8')
  }

  it('creates the output directory and index.ts', async () => {
    const nested = path.join(tempDir, 'a', 'b', 'c')
    await generateRestClient(testDmmf, nested)
    const stat = await fs.stat(path.join(nested, 'index.ts'))
    expect(stat.isFile()).toBe(true)
  })

  it('includes the auto-generated banner', async () => {
    await generateRestClient(testDmmf, tempDir)
    expect(await readOutput()).toContain('auto-generated by @prisma/rest-api-client-generator')
  })

  it('generates enum union type', async () => {
    await generateRestClient(testDmmf, tempDir)
    expect(await readOutput()).toContain("export type Role = 'USER' | 'ADMIN'")
  })

  it('generates model interface with correct TypeScript types', async () => {
    await generateRestClient(testDmmf, tempDir)
    const content = await readOutput()
    expect(content).toContain('export interface User {')
    expect(content).toContain('id: number')
    expect(content).toContain('email: string')
    expect(content).toContain('name: string | null')
    expect(content).toContain('role: Role')
    // Relations must not appear in the interface.
    expect(content).not.toMatch(/posts:\s/)
  })

  it('generates WhereUniqueInput with id and unique fields as optional', async () => {
    await generateRestClient(testDmmf, tempDir)
    const content = await readOutput()
    expect(content).toContain('export type UserWhereUniqueInput = {')
    expect(content).toContain('id?: number')
    expect(content).toContain('email?: string')
    // Non-unique, non-id fields must not appear.
    expect(content).not.toMatch(/UserWhereUniqueInput[\s\S]*?name\?/)
  })

  it('generates CreateInput with required fields required and optional/defaulted fields optional', async () => {
    await generateRestClient(testDmmf, tempDir)
    const content = await readOutput()
    expect(content).toContain('export type UserCreateInput = {')
    // email: required, no default → required property
    expect(content).toMatch(/UserCreateInput[\s\S]*?email: string/)
    // name: optional → optional property with null
    expect(content).toMatch(/UserCreateInput[\s\S]*?name\?: string \| null/)
    // role: required but has default → optional property
    expect(content).toMatch(/UserCreateInput[\s\S]*?role\?: Role \| null/)
    // id: has default (autoincrement) → optional property
    expect(content).toMatch(/UserCreateInput[\s\S]*?id\?: number \| null/)
  })

  it('generates UpdateInput with all non-id fields as optional', async () => {
    await generateRestClient(testDmmf, tempDir)
    const content = await readOutput()
    expect(content).toContain('export type UserUpdateInput = {')
    expect(content).toMatch(/UserUpdateInput[\s\S]*?email\?: string \| null/)
    expect(content).toMatch(/UserUpdateInput[\s\S]*?name\?: string \| null/)
    // id is excluded from UpdateInput
    expect(content).not.toMatch(/UserUpdateInput \{[^}]*\bid\b/)
  })

  it('generates FindManyParams type', async () => {
    await generateRestClient(testDmmf, tempDir)
    const content = await readOutput()
    expect(content).toContain('export type UserFindManyParams = {')
    expect(content).toContain('where?: Partial<User>')
    expect(content).toContain('take?: number')
    expect(content).toContain('skip?: number')
  })

  it('generates PrismaRestClientConfig and PrismaRestClientError', async () => {
    await generateRestClient(testDmmf, tempDir)
    const content = await readOutput()
    expect(content).toContain('export interface PrismaRestClientConfig {')
    expect(content).toContain('baseUrl: string')
    expect(content).toContain('export class PrismaRestClientError extends Error {')
    expect(content).toContain("this.name = 'PrismaRestClientError'")
  })

  it('generates model REST client class with all CRUD methods', async () => {
    await generateRestClient(testDmmf, tempDir)
    const content = await readOutput()
    expect(content).toContain('export class UserRestClient {')
    expect(content).toContain('async findMany(params?: UserFindManyParams): Promise<User[]>')
    expect(content).toContain('async findUnique(where: UserWhereUniqueInput): Promise<User | null>')
    expect(content).toContain('async create(data: UserCreateInput): Promise<User>')
    expect(content).toContain('async update(where: UserWhereUniqueInput, data: UserUpdateInput): Promise<User>')
    expect(content).toContain('async delete(where: UserWhereUniqueInput): Promise<User>')
  })

  it('uses the correct URL resource path in the client methods', async () => {
    await generateRestClient(testDmmf, tempDir)
    const content = await readOutput()
    // findMany uses lowercase-first model name as path segment
    expect(content).toContain("'GET', 'user'")
    expect(content).toContain("'GET', 'user/unique'")
    expect(content).toContain("'POST', 'user'")
    expect(content).toContain("'PATCH', 'user'")
    expect(content).toContain("'DELETE', 'user'")
  })

  it('generates the root PrismaRestClient with a property per model', async () => {
    await generateRestClient(testDmmf, tempDir)
    const content = await readOutput()
    expect(content).toContain('export class PrismaRestClient {')
    expect(content).toContain('readonly user: UserRestClient')
    expect(content).toContain('this.user = new UserRestClient(config)')
  })

  it('generates valid output for a schema with no enums', async () => {
    const noEnumDmmf: typeof testDmmf = {
      ...testDmmf,
      datamodel: { ...testDmmf.datamodel, enums: [] },
    }
    await generateRestClient(noEnumDmmf, tempDir)
    const content = await readOutput()
    expect(content).toContain('export interface User {')
    expect(content).not.toContain('export type Role')
  })
})
